#include <vector>
#include <set>
#include <algorithm>

using namespace std;

long long solve(vector<long long> value, vector<long long> limit) {
    // Create a vector of pairs containing value and limit for each element
    vector<pair<long long, long long>> elements;
    for (int i = 0; i < value.size(); ++i) {
        elements.push_back({value[i], limit[i]});
    }

    // Sort elements by value in descending order and by limit in ascending order
    sort(elements.begin(), elements.end(), [](const pair<long long, long long>& a, const pair<long long, long long>& b) {
        if (a.first != b.first) return a.first > b.first;
        return a.second < b.second;
    });

    set<long long> activatedLimits;
    long long activeCount = 0;
    long long total = 0;

    for (const auto& elem : elements) {
        // Check if the element can be activated
        if (activeCount < elem.second && activatedLimits.find(elem.second) == activatedLimits.end()) {
            // Activate the element
            total += elem.first;
            activatedLimits.insert(elem.second);
            activeCount++;
        }
    }

    return total;
}
