function solve(value: number[], limit: number[]): number {
    // Sort the elements based on their value in descending order
    // and their limit in ascending order to prioritize higher value elements
    const elements = value.map((v, i) => ({ v, l: limit[i] }))
    elements.sort((a, b) => {
        if (a.v !== b.v) return b.v - a.v;
        return a.l - b.l;
    });

    let activeCount = 0;
    let total = 0;
    const activated = new Set<number>();

    for (const elem of elements) {
        // Check if the element can be activated
        if (activeCount < elem.l && !activated.has(elem.l)) {
            // Activate the element
            total += elem.v;
            activated.add(elem.l);
            activeCount++;
        }
    }

    return total;
}
